window.NZ_OPISY=window.NZ_OPISY||{};window.NZ_OPISY["f"]={"Franciszek": "<b>Franciszek</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie wywodzące się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a> określenia <i>francesco</i> oznaczającego \"Francuza, Francuzika\", jakim kupiec Piotr Bernardone (ojciec <a href=\"https://pl.wikipedia.org/wiki/Franciszek_z_Asy%C5%BCu\" target=\"_blank\" rel=\"noopener noreferrer\">św. Franciszka z Asyżu</a>) nazwał swego syna Jana, gdy ten wrócił z Francji. W Asyżu zaczęto powszechnie nazywać chłopca tym określeniem i pod takim imieniem znany jest powszechnie.", "Filip": "Nosił je np. <a href=\"https://pl.wikipedia.org/wiki/Filip_II_Macedo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Filip II Macedoński</a>, ojciec <a href=\"https://pl.wikipedia.org/wiki/Aleksander_Macedo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksandra Wielkiego</a>. Żeńskie odpowiedniki tego imienia to <a href=\"https://pl.wikipedia.org/wiki/Filipina\" target=\"_blank\" rel=\"noopener noreferrer\">Filipina</a>, <a href=\"https://pl.wikipedia.org/wiki/Filipa\" target=\"_blank\" rel=\"noopener noreferrer\">Filipa</a>. Nazwiska pochodzące od Filipa: <a href=\"https://pl.wikipedia.org/wiki/Filipowicz\" target=\"_blank\" rel=\"noopener noreferrer\">Filipowicz</a>, Filipczak, Filipek, Filipowski, Filipkowski. Nazwa państwa <a href=\"https://pl.wikipedia.org/wiki/Filipiny\" target=\"_blank\" rel=\"noopener noreferrer\">Filipiny</a> pochodzi od imienia króla Hiszpanii <a href=\"https://pl.wikipedia.org/wiki/Filip_II_Habsburg\" target=\"_blank\" rel=\"noopener noreferrer\">Filipa II Habsburga</a>.", "Fabian": "<b>Fabian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „należący do Fabiusza” (mężczyzny z rodu Fabiuszów). Nazwa rodowa Fabiuszy wywodzi się zaś od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>faba</em> (<a href=\"https://pl.wikipedia.org/wiki/B%C3%B3b\" target=\"_blank\" rel=\"noopener noreferrer\">bób</a>) i pierwotnie oznaczała osobę zajmującą się uprawą bobu. Chrześcijańskim patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Fabian_(papie%C5%BC)\" target=\"_blank\" rel=\"noopener noreferrer\">św.&#160;Fabian, papież</a>.", "Feliks": "<b>Feliks</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>felix</em> – łaskawy, szczęśliwy) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Żeńskie odpowiedniki: <a href=\"https://pl.wikipedia.org/wiki/Feliksa\" target=\"_blank\" rel=\"noopener noreferrer\">Feliksa</a>, <a href=\"https://pl.wikipedia.org/wiki/Felicja\" target=\"_blank\" rel=\"noopener noreferrer\">Felicja</a>.", "Florian": "<b>Florian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego „kwitnący kwiat”. W Polsce używane bywało w formie <b>Tworzyjan</b>. Od Floriana wywodzi się także czeski neologizm <i>Květoslav</i>.", "Fryderyk": "<b>Fryderyk</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niem.</a> <i>Friedrich</i>). Dawniej adaptowane do języka polskiego w formach <i>Biedrzych</i>, <i>Berdych</i>.", "Ferdynand": "<b>Ferdynand</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów oznaczających „pokój” i „odważny, śmiały” (por. <a href=\"https://pl.wikipedia.org/wiki/Winand\" target=\"_blank\" rel=\"noopener noreferrer\">Winand</a>).", "Felicjan": "<b>Felicjan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, powstałe jako przydomek od imienia <a href=\"https://pl.wikipedia.org/wiki/Feliks\" target=\"_blank\" rel=\"noopener noreferrer\">Feliks</a> i bliźniacze do niego znaczeniowo. <a href=\"https://pl.wikipedia.org/wiki/Ko%C5%9Bci%C3%B3%C5%82_katolicki\" target=\"_blank\" rel=\"noopener noreferrer\">Kościół katolicki</a> notuje licznych świętych o tym imieniu.", "Fiodor": "W Polsce nadawane co najmniej od XIII wieku i zapisywane m.in. w postaci: <i>Tader</i>, <i>Chodor</i> (wschsł.), <i>Teodor</i>, <i>Todor</i>, <i>C(z)ader</i>, <i>C(z)eder</i>. Odpowiednikiem znaczeniowym tego imienia wśród imion staropolskich jest <a href=\"https://pl.wikipedia.org/wiki/Dadzbog\" target=\"_blank\" rel=\"noopener noreferrer\">Dadzbog</a>, <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%BCydar_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bożydar</a>, <a href=\"https://pl.wikipedia.org/wiki/Bogdan\" target=\"_blank\" rel=\"noopener noreferrer\">Bogdan</a>, <a href=\"https://pl.wikipedia.org/wiki/Bogdan\" target=\"_blank\" rel=\"noopener noreferrer\">Bohdan</a>.", "Faustyn": "<b>Faustyn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od rzymskiego nazwiska <i>Faustinus</i>, które pierwotnie oznaczało „pochodzący od <a href=\"https://pl.wikipedia.org/wiki/Faust_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Fausta</a>, należący do Fausta”. Imię to nosiło wielu świętych, a jednym ze znanych jest św. Faustyn, wspominany 15 lutego ze swoim bratem, św. <a href=\"https://pl.wikipedia.org/wiki/Jowita\" target=\"_blank\" rel=\"noopener noreferrer\">Jowitą</a>. Łacińska grupa, od której imię to pochodzi (<i>faustus</i> — „błogi, pomyślny”, ale także <i>faveo, favi, fautum</i> — „sprzyjać, być przychylnym”) nie ma pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_indoeuropejskie\" target=\"_blank\" rel=\"noopener noreferrer\">indoeuropejskiego</a> oraz pewnych odpowiedników w żadnym języku indoeuropejskim.", "Ferenc": "<b>Franciszek</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie wywodzące się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a> określenia <i>francesco</i> oznaczającego \"Francuza, Francuzika\", jakim kupiec Piotr Bernardone (ojciec <a href=\"https://pl.wikipedia.org/wiki/Franciszek_z_Asy%C5%BCu\" target=\"_blank\" rel=\"noopener noreferrer\">św. Franciszka z Asyżu</a>) nazwał swego syna Jana, gdy ten wrócił z Francji. W Asyżu zaczęto powszechnie nazywać chłopca tym określeniem i pod takim imieniem znany jest powszechnie.", "Flawiusz": "<b>Flawiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <a href=\"https://pl.wikipedia.org/wiki/Flawiusze\" target=\"_blank\" rel=\"noopener noreferrer\">Flawiuszów</a>. Po łacinie znaczy \"złoty\".", "Fares": "<b>Peres</b> lub <b>Fares</b> − postać biblijna z <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Rodzaju\" target=\"_blank\" rel=\"noopener noreferrer\">Księgi Rodzaju</a>, syn <a href=\"https://pl.wikipedia.org/wiki/Juda_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Judy</a> i jego synowej <a href=\"https://pl.wikipedia.org/wiki/Tamar_(synowa_Judy)\" target=\"_blank\" rel=\"noopener noreferrer\">Tamar</a>. Jego bratem bliźniakiem był Zerach, a braćmi przyrodnimi <a href=\"https://pl.wikipedia.org/wiki/Er_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Er</a>, <a href=\"https://pl.wikipedia.org/wiki/Onan\" target=\"_blank\" rel=\"noopener noreferrer\">Onan</a> i <a href=\"https://pl.wikipedia.org/wiki/Szela\" target=\"_blank\" rel=\"noopener noreferrer\">Szela</a>. Od Peresa pochodzi ród Parsytów.", "Florent": "<b>Florencjusz</b>, <b>Florenty</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, występujące w Polsce już w <a href=\"https://pl.wikipedia.org/wiki/XII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XII wieku</a> (<a href=\"https://pl.wikipedia.org/wiki/1175\" target=\"_blank\" rel=\"noopener noreferrer\">1175</a> r.). Powstało ono od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomka</a> <i>Florentius</i>, utworzonego poprzez dodanie <a href=\"https://pl.wikipedia.org/wiki/Przyrostek\" target=\"_blank\" rel=\"noopener noreferrer\">przyrostka</a> <i>-ius</i> od innego przydomka, <i>Florens</i> (łac. <i>florens</i>, <i>-ntis</i> — \"kwitnący\"). Istnieją liczni święci patroni tego imienia (nawet dwudziestu), m.in. św. <a href=\"https://pl.wikipedia.org/wiki/Florencjusz_z_Populonii\" target=\"_blank\" rel=\"noopener noreferrer\">Florencjusz z Populonii</a>, biskup (<a href=\"https://pl.wikipedia.org/wiki/IV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">IV wiek</a>).", "Fortunat": "<b>Fortunat</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>.", "Fidelis": "<b>Fidelis</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>fidelis</em> – „wierny, pewny”. Oznacza zatem człowieka „pełnego wiary”. Współczesną jego formą w języku hiszpańskim jest Fidel.", "Fan": "Nazwa wywodzi się od zapisu skróconej formy słowa <a href=\"https://pl.wikipedia.org/wiki/Fanatyzm\" target=\"_blank\" rel=\"noopener noreferrer\">fanatyk</a>. Nie posiada jednak pejoratywnego znaczenia, a nawet ma pozytywny wydźwięk.", "Flawian": "<b>Flawian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od nazwy <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <a href=\"https://pl.wikipedia.org/wiki/Flawiusze\" target=\"_blank\" rel=\"noopener noreferrer\">Flawiuszów</a>. Oznacza <i>flavus</i> - \"żółty, płowy, złoty\". Wśród patronów - m.in. św. Flawian II, <a href=\"https://pl.wikipedia.org/wiki/Patriarcha_Antiochii\" target=\"_blank\" rel=\"noopener noreferrer\">biskup Antiochii</a>.", "Filemon": "<b>Filemon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>philé</i> – „miłuję, kocham” lub od <i>phil-mosýn</i> – „przyjazność, życzliwość”, czyli „życzliwy, przyjazny”. Żyjący <a href=\"https://pl.wikipedia.org/wiki/Nowy_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">w czasach biblijnych</a> <a href=\"https://pl.wikipedia.org/wiki/Filemon_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Św. Filemon</a> był <a href=\"https://pl.wikipedia.org/wiki/List_do_Filemona\" target=\"_blank\" rel=\"noopener noreferrer\">jednym z adresatów listów</a> <a href=\"https://pl.wikipedia.org/wiki/Pawe%C5%82_z_Tarsu\" target=\"_blank\" rel=\"noopener noreferrer\">św. Pawła</a>.", "Frydolin": "<b>Frydolin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Nosił to imię <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aw._Frydolin\" target=\"_blank\" rel=\"noopener noreferrer\">św. Frydolin</a>.", "Festus": "<b>Festus</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego \"święto\" lub \"festiwal\". Pojawia się w <a href=\"https://pl.wikipedia.org/wiki/Nowy_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Nowym Testamencie</a> jako przydomek rzymskiego urzędnika. Jest to imię dwóch świętych katolickich.", "Faust": "<b>Faust</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>faustus</em>, „błogi, szczęśliwy”), należące do niedużej grupy najstarszych <a href=\"https://pl.wikipedia.org/wiki/Imiona_%C5%82aci%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion rzymskich</a> (imion właściwych, <i>praenomen</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Marek\" target=\"_blank\" rel=\"noopener noreferrer\">Marek</a>, <a href=\"https://pl.wikipedia.org/wiki/Tyberiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Tyberiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Tytus\" target=\"_blank\" rel=\"noopener noreferrer\">Tytus</a>), i oznaczające „szczęśliwie rosnący”. Łacińska grupa, od której imię to pochodzi (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>faustus</em> – \"błogi, pomyślny\", ale także <i>faveo, favi, fautum</i> – \"sprzyjać, być przychylnym\") nie ma pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_indoeuropejskie\" target=\"_blank\" rel=\"noopener noreferrer\">indoeuropejskiego</a> oraz pewnych odpowiedników w żadnym języku indoeuropejskim.", "Flemming": "<b>Flemming (<i>Flemingowie</i>, <i>Flemmingowie</i>, <i>von Flemming</i>)</b> – <a href=\"https://pl.wikipedia.org/wiki/Niemcy\" target=\"_blank\" rel=\"noopener noreferrer\">zniemczony</a> <a href=\"https://pl.wikipedia.org/wiki/Flamandowie\" target=\"_blank\" rel=\"noopener noreferrer\">flamandzki</a> <a href=\"https://pl.wikipedia.org/wiki/R%C3%B3d\" target=\"_blank\" rel=\"noopener noreferrer\">ród</a> <a href=\"https://pl.wikipedia.org/wiki/Szlachta\" target=\"_blank\" rel=\"noopener noreferrer\">szlachecki</a>, wywodzący się z <a href=\"https://pl.wikipedia.org/wiki/Flandria_(region)\" target=\"_blank\" rel=\"noopener noreferrer\">Flandrii</a> (dzisiejsza <a href=\"https://pl.wikipedia.org/wiki/Belgia\" target=\"_blank\" rel=\"noopener noreferrer\">Belgia</a>), zamieszkujący <a href=\"https://pl.wikipedia.org/wiki/Pomorze_Zachodnie\" target=\"_blank\" rel=\"noopener noreferrer\">Pomorze Zachodnie</a> od okresu <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowiecza</a> (XIII w.) do XIX/XX wieku.", "Filon": "<b>Filon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, gr. <i>Φιλων (Filon)</i>, które pochodzi od <i>φιλεω (fileo)</i> – \"kochać\" i oznacza \"kochający\". Patronem tego imienia jest św. Filon, wspominany razem ze św. Agatopodem.", "Florentyn": "<b>Florentyn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, genetycznie wtórne cognomen <i>Florentinus</i>, utworzone od pierwotnego <i>Florentius</i> Istnieją liczni święci patroni tego imienia, m.in. św. Florentyn (+357), męczennik burgundzki wspominany <a href=\"https://pl.wikipedia.org/wiki/27_wrze%C5%9Bnia\" target=\"_blank\" rel=\"noopener noreferrer\">27 września</a>.", "Fionn": "\"Fionn” (lub „Finn”) to w rzeczywistości pseudonim oznaczający „jasny” – w odniesieniu do koloru włosów, a w niektórych wersjach – również „biały”, co dotyczy czystości.", "Fabiusz": "<b>Fabiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się nazwy rzymskiego rodu Fabiuszów, która z kolei pochodzi od łacińskiego <i>faba</i> - \"bób\". Wśród patronów tego imienia — św. Fabiusz, wspominany razem ze swoimi towarzyszami, św. Bassusem, <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Maksym\" target=\"_blank\" rel=\"noopener noreferrer\">Maksymem</a> i <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Antym\" target=\"_blank\" rel=\"noopener noreferrer\">Antymem</a>.", "Firmin": "<b>Firmin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „należący do <a href=\"https://pl.wikipedia.org/wiki/Firmus_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Firmusa</a>” lub stanowiące spieszczenie imienia <a href=\"https://pl.wikipedia.org/wiki/Firmus_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Firmus</a>, które z kolei pochodzi od słowa <i>firmus</i>, 'mocny, pewny, stały, trwały'. Wśród patronów - <a href=\"https://pl.wikipedia.org/wiki/Firmin_(biskup_Amiens)\" target=\"_blank\" rel=\"noopener noreferrer\">św. Firmin (biskup Amiens)</a>.", "Firman": "<b>Firman</b> – w dawnych państwach <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmańskich</a> określenie oficjalnych dokumentów wystawianych przez władcę (<a href=\"https://pl.wikipedia.org/wiki/Su%C5%82tan\" target=\"_blank\" rel=\"noopener noreferrer\">sułtana</a>). Firman zawierał osobisty pisemny rozkaz i był pieczętowany sułtańską pieczęcią. Słowo pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">perskiego</a> słowa <i>farmân</i> (فرمان), znaczącego <i>dekret</i> lub <i>nakaz</i>. W sułtańskiej Turcji używana była forma <i>ferman</i>.", "Frode": "<b>Frode</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">Język staronordyjski</a>: <i>Frōði</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">język staroangielski</a>: <i>Frōda</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_%C5%9Brednio-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">język średnio-wysoko-niemiecki</a>: <i>Vruote</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_norweski\" target=\"_blank\" rel=\"noopener noreferrer\">język norweski</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_du%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">duński</a>: <i>Frode</i>) – norweskie, oraz duńskie imię męskie oznaczające „mądry”, „uczony” lub „sprytny”. Miało je nosić wielu legendarnych królów <a href=\"https://pl.wikipedia.org/wiki/Legendarni_w%C5%82adcy_Danii\" target=\"_blank\" rel=\"noopener noreferrer\">Danii</a> według dzieł takich jak: <i><a href=\"https://pl.wikipedia.org/wiki/Beowulf\" target=\"_blank\" rel=\"noopener noreferrer\">Beowulf</a></i>, <i><a href=\"https://pl.wikipedia.org/wiki/Edda_m%C5%82odsza\" target=\"_blank\" rel=\"noopener noreferrer\">Edda młodsza</a></i>, <i><a href=\"https://pl.wikipedia.org/wiki/Gesta_Danorum\" target=\"_blank\" rel=\"noopener noreferrer\">Gesta Danorum</a></i>, <i><a href=\"https://pl.wikipedia.org/wiki/Heimskringla\" target=\"_blank\" rel=\"noopener noreferrer\">Saga o Ynglingach</a></i>, czy <i>Grottasöngr</i>. <i>Gesta Danorum</i> wymienia aż sześciu władców o tym imieniu. Forma „Frōði” jest w dalszym ciągu używana w języku <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_islandzki\" target=\"_blank\" rel=\"noopener noreferrer\">islandzkim</a>, czy <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_farerski\" target=\"_blank\" rel=\"noopener noreferrer\">farerskim</a>. Zlatynizowaną formą imienia jest „Frotho”, bądź „Frodo”. Została ona użyta przez <a href=\"https://pl.wikipedia.org/wiki/J.R.R._Tolkien\" target=\"_blank\" rel=\"noopener noreferrer\">Johna Ronalda Reuela Tolkiena</a> w trylogii <a href=\"https://pl.wikipedia.org/wiki/W%C5%82adca_pier%C5%9Bcieni\" target=\"_blank\" rel=\"noopener noreferrer\">Władca pierścieni</a>. Jeden z bohaterów dzieła nosi imię <a href=\"https://pl.wikipedia.org/wiki/Frodo_Baggins\" target=\"_blank\" rel=\"noopener noreferrer\">Frodo</a>. W <a href=\"https://pl.wikipedia.org/wiki/2008\" target=\"_blank\" rel=\"noopener noreferrer\">2008</a> roku imię Frode nosiło w <a href=\"https://pl.wikipedia.org/wiki/Norwegia\" target=\"_blank\" rel=\"noopener noreferrer\">Norwegii</a> 11384 osób, w <a href=\"https://pl.wikipedia.org/wiki/Dania\" target=\"_blank\" rel=\"noopener noreferrer\">Danii</a> około 1413, a w <a href=\"https://pl.wikipedia.org/wiki/Szwecja\" target=\"_blank\" rel=\"noopener noreferrer\">Szwecji</a> około 307 mężczyzn.", "Fintan": "<b>Fintan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Celtowie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>, polski odpowiednik celtyckiego imienia <i>Fionntán</i>, które prawdopodobnie oznaczało \"biały ogień\" lub \"biały byk\". Jest to imię wielu irlandzkich świętych.", "Florencjusz": "<b>Florencjusz</b>, <b>Florenty</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, występujące w Polsce już w <a href=\"https://pl.wikipedia.org/wiki/XII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XII wieku</a> (<a href=\"https://pl.wikipedia.org/wiki/1175\" target=\"_blank\" rel=\"noopener noreferrer\">1175</a> r.). Powstało ono od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomka</a> <i>Florentius</i>, utworzonego poprzez dodanie <a href=\"https://pl.wikipedia.org/wiki/Przyrostek\" target=\"_blank\" rel=\"noopener noreferrer\">przyrostka</a> <i>-ius</i> od innego przydomka, <i>Florens</i> (łac. <i>florens</i>, <i>-ntis</i> — \"kwitnący\"). Istnieją liczni święci patroni tego imienia (nawet dwudziestu), m.in. św. <a href=\"https://pl.wikipedia.org/wiki/Florencjusz_z_Populonii\" target=\"_blank\" rel=\"noopener noreferrer\">Florencjusz z Populonii</a>, biskup (<a href=\"https://pl.wikipedia.org/wiki/IV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">IV wiek</a>).", "Filaret": "<b>Filaret</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, którego patronem jest św. Filaret, zwany Kalabryjczykiem (<a href=\"https://pl.wikipedia.org/wiki/XI_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XI wiek</a>).", "Feres": "<b>Feres</b> (gr. <i>Phéres</i>) − postać w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii greckiej</a>. Był synem <a href=\"https://pl.wikipedia.org/wiki/Kreteus\" target=\"_blank\" rel=\"noopener noreferrer\">Kreteusa</a> i <a href=\"https://pl.wikipedia.org/wiki/Tyro\" target=\"_blank\" rel=\"noopener noreferrer\">Tyro</a> oraz ojcem <a href=\"https://pl.wikipedia.org/wiki/Admet\" target=\"_blank\" rel=\"noopener noreferrer\">Admeta</a>. Założył miasto <a href=\"https://pl.wikipedia.org/wiki/Feraj\" target=\"_blank\" rel=\"noopener noreferrer\">Feraj</a> w <a href=\"https://pl.wikipedia.org/wiki/Tesalia\" target=\"_blank\" rel=\"noopener noreferrer\">Tesalii</a>, którego nazwa pochodzi także od jego imienia. Będąc już bardzo starym, nie chciał spełnić prośby syna, gdy ten szukał kogoś, kto zgodziłby się za niego umrzeć.", "Ferman": "<b>Firman</b> – w dawnych państwach <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmańskich</a> określenie oficjalnych dokumentów wystawianych przez władcę (<a href=\"https://pl.wikipedia.org/wiki/Su%C5%82tan\" target=\"_blank\" rel=\"noopener noreferrer\">sułtana</a>). Firman zawierał osobisty pisemny rozkaz i był pieczętowany sułtańską pieczęcią. Słowo pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">perskiego</a> słowa <i>farmân</i> (فرمان), znaczącego <i>dekret</i> lub <i>nakaz</i>. W sułtańskiej Turcji używana była forma <i>ferman</i>.", "Farys": "<b>Farys</b> – <a href=\"https://pl.wikipedia.org/wiki/Muzu%C5%82manin\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmański</a> <a href=\"https://pl.wikipedia.org/wiki/Je%C5%BAdziec\" target=\"_blank\" rel=\"noopener noreferrer\">jeździec</a>, profesjonalny <a href=\"https://pl.wikipedia.org/wiki/Wojownik\" target=\"_blank\" rel=\"noopener noreferrer\">wojownik</a> (<a href=\"https://pl.wikipedia.org/wiki/Mamelucy\" target=\"_blank\" rel=\"noopener noreferrer\">mameluk</a>), wojownik–niewolnik <a href=\"https://pl.wikipedia.org/wiki/Ghilman\" target=\"_blank\" rel=\"noopener noreferrer\">ghilman</a>, odpowiednik europejskiego <a href=\"https://pl.wikipedia.org/wiki/Rycerstwo\" target=\"_blank\" rel=\"noopener noreferrer\">rycerza</a>. Samo słowo w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">języku arabskim</a> oznaczało jeźdźca (Nicolle, Saracen Faris, strona 3). Uzbrojony w następujące rodzaje broni (choć nie we wszystkie naraz): <a href=\"https://pl.wikipedia.org/wiki/%C5%81uk_(bro%C5%84)\" target=\"_blank\" rel=\"noopener noreferrer\">łuk</a>, <a href=\"https://pl.wikipedia.org/wiki/Miecz\" target=\"_blank\" rel=\"noopener noreferrer\">miecz</a>, <a href=\"https://pl.wikipedia.org/wiki/Szabla\" target=\"_blank\" rel=\"noopener noreferrer\">szablę</a>, <a href=\"https://pl.wikipedia.org/wiki/W%C5%82%C3%B3cznia\" target=\"_blank\" rel=\"noopener noreferrer\">włócznię</a>, <a href=\"https://pl.wikipedia.org/wiki/Oszczep_(bro%C5%84)\" target=\"_blank\" rel=\"noopener noreferrer\">oszczep</a>, <a href=\"https://pl.wikipedia.org/wiki/Top%C3%B3r\" target=\"_blank\" rel=\"noopener noreferrer\">topór</a> (<i>tabarzin</i>), <a href=\"https://pl.wikipedia.org/wiki/Czekan_(bro%C5%84)\" target=\"_blank\" rel=\"noopener noreferrer\">czekan</a>, <a href=\"https://pl.wikipedia.org/wiki/Nadziak\" target=\"_blank\" rel=\"noopener noreferrer\">nadziak</a>, <a href=\"https://pl.wikipedia.org/wiki/Kopia_(bro%C5%84)\" target=\"_blank\" rel=\"noopener noreferrer\">kopię</a>, <a href=\"https://pl.wikipedia.org/wiki/Maczuga_(bro%C5%84)\" target=\"_blank\" rel=\"noopener noreferrer\">maczugę</a> – sztukę posługiwania się tym <a href=\"https://pl.wikipedia.org/wiki/Bro%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">orężem</a> zwaną <i>furusiya</i> ćwiczono w <a href=\"https://pl.wikipedia.org/wiki/Koszary\" target=\"_blank\" rel=\"noopener noreferrer\">koszarach</a>, na <a href=\"https://pl.wikipedia.org/wiki/Majdan_(urbanistyka)\" target=\"_blank\" rel=\"noopener noreferrer\">majdanie</a> jak i podczas <a href=\"https://pl.wikipedia.org/wiki/Polowanie\" target=\"_blank\" rel=\"noopener noreferrer\">polowania</a> na dzikie zwierzęta. Ale furusiya to nie tylko walka bronią, ale również jazda konna, zapasy, musztra, strzelanie z kuszy, <a href=\"https://pl.wikipedia.org/wiki/Polo_(sport)\" target=\"_blank\" rel=\"noopener noreferrer\">polo</a>, wyścigi konne, walka piesza z bronią, posłuszeństwo, nauka taktyki i strategii, posiadanie dobrej jakości broni oraz pancerza, wytrwałość i zwinność (Nicolle, strona 8-9). Według <i>Siyast Nama</i> trening farysa zabierał 8 lat, i był stopniowany co do użycia broni, konia i pancerza, a także obowiązków i pozycji farysa (Nicolle, strona 10). Wojownicy muzułmańscy nosili długie włosy i wąsy w odróżnieniu od populacji cywilnej (Nicolle, Saracen Faris, strona 5). W oddziałach <a href=\"https://pl.wikipedia.org/wiki/Jazda\" target=\"_blank\" rel=\"noopener noreferrer\">kawalerii</a> złożonych z farysów służyli <a href=\"https://pl.wikipedia.org/wiki/Turcy\" target=\"_blank\" rel=\"noopener noreferrer\">Turcy</a>, <a href=\"https://pl.wikipedia.org/wiki/Ormianie\" target=\"_blank\" rel=\"noopener noreferrer\">Ormianie</a>, <a href=\"https://pl.wikipedia.org/wiki/Kurdowie\" target=\"_blank\" rel=\"noopener noreferrer\">Kurdowie</a>, <a href=\"https://pl.wikipedia.org/wiki/Grecy\" target=\"_blank\" rel=\"noopener noreferrer\">Grecy</a>, <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">Słowianie</a>, <a href=\"https://pl.wikipedia.org/wiki/Ludy_ira%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">Irańczycy</a> (<a href=\"https://pl.wikipedia.org/wiki/Persowie\" target=\"_blank\" rel=\"noopener noreferrer\">Persowie</a>) i <a href=\"https://pl.wikipedia.org/wiki/Arabowie\" target=\"_blank\" rel=\"noopener noreferrer\">Arabowie</a>. Słynnym <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowiecznym</a> farysem był <a href=\"https://pl.wikipedia.org/wiki/Usama_Ibn_Munkiz\" target=\"_blank\" rel=\"noopener noreferrer\">Usama Ibn Munkiz</a>, który pozostawił po sobie pamiętnik \"Kitab al-itibar\".", "Faro": "<b>Faro</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, od germ. <i>fara</i> – \"podróż\". Patronem tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Faro_z_Meaux\" target=\"_blank\" rel=\"noopener noreferrer\">Faro</a>, biskup <a href=\"https://pl.wikipedia.org/wiki/Meaux\" target=\"_blank\" rel=\"noopener noreferrer\">Meaux</a> (<a href=\"https://pl.wikipedia.org/wiki/VII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VII wiek</a>).", "Florenty": "<b>Florencjusz</b>, <b>Florenty</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, występujące w Polsce już w <a href=\"https://pl.wikipedia.org/wiki/XII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XII wieku</a> (<a href=\"https://pl.wikipedia.org/wiki/1175\" target=\"_blank\" rel=\"noopener noreferrer\">1175</a> r.). Powstało ono od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomka</a> <i>Florentius</i>, utworzonego poprzez dodanie <a href=\"https://pl.wikipedia.org/wiki/Przyrostek\" target=\"_blank\" rel=\"noopener noreferrer\">przyrostka</a> <i>-ius</i> od innego przydomka, <i>Florens</i> (łac. <i>florens</i>, <i>-ntis</i> — \"kwitnący\"). Istnieją liczni święci patroni tego imienia (nawet dwudziestu), m.in. św. <a href=\"https://pl.wikipedia.org/wiki/Florencjusz_z_Populonii\" target=\"_blank\" rel=\"noopener noreferrer\">Florencjusz z Populonii</a>, biskup (<a href=\"https://pl.wikipedia.org/wiki/IV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">IV wiek</a>).", "Felin": "<b>Felin</b> — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, którego patronem jest św. Felin, towarzysz św. Gratyniana i razem z nim patron <a href=\"https://pl.wikipedia.org/wiki/Arona_(W%C5%82ochy)\" target=\"_blank\" rel=\"noopener noreferrer\">Arony</a>. <a href=\"https://pl.wikipedia.org/wiki/Gratynian_i_Felin\" target=\"_blank\" rel=\"noopener noreferrer\">Gratynian i Felin</a> zostali męczennikami za czasów cesarza <a href=\"https://pl.wikipedia.org/wiki/Trajan_Decjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Decjusza</a>. Relikwie przeniesiono do <a href=\"https://pl.wikipedia.org/wiki/Opactwo\" target=\"_blank\" rel=\"noopener noreferrer\">opactwa</a> w Aronie, gdzie opatem–komendatariuszem był w <a href=\"https://pl.wikipedia.org/wiki/1550\" target=\"_blank\" rel=\"noopener noreferrer\">1550</a> <a href=\"https://pl.wikipedia.org/wiki/Karol_Boromeusz\" target=\"_blank\" rel=\"noopener noreferrer\">Karol Boromeusz</a>. Obecnie opactwo jest zlikwidowane, ale kościół pod wezwaniem męczenników istnieje po dziś dzień.", "Fumio": "<b>Fumio</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;ふみお, フミオ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Fulbert": "<b>Fulbert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, o nieznanym znaczeniu. Być może wariant imienia <a href=\"https://pl.wikipedia.org/wiki/Filibert\" target=\"_blank\" rel=\"noopener noreferrer\">Filibert</a>. Patronem tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Fulbert_z_Chartres\" target=\"_blank\" rel=\"noopener noreferrer\">Fulbert</a>, biskup <a href=\"https://pl.wikipedia.org/wiki/Chartres\" target=\"_blank\" rel=\"noopener noreferrer\">Chartres</a> (zm. <a href=\"https://pl.wikipedia.org/wiki/1028\" target=\"_blank\" rel=\"noopener noreferrer\">1028</a>).", "Finan": "Istnieją zapiski <a href=\"https://pl.wikipedia.org/wiki/Hagiografia\" target=\"_blank\" rel=\"noopener noreferrer\">hagiograficzne</a> opisujące blisko dziesięć postaci świętych noszących to imię. Jednak nie można zweryfikować historyczności tych postaci gdyż w okresie średniowiecza kopiści, a także późniejsi badacze dopuścili się błędów mieszając imię Finan z imionami Finian, Findian i Fridian. Mimo iż brak źródeł historycznych potwierdzających pochodzenie Finana uważany jest za <a href=\"https://pl.wikipedia.org/wiki/Irlandczycy\" target=\"_blank\" rel=\"noopener noreferrer\">Irlandczyka</a>.", "Fama": "Jej <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">greckim</a> odpowiednikiem była <a href=\"https://pl.wikipedia.org/wiki/Feme\" target=\"_blank\" rel=\"noopener noreferrer\">Feme</a>.", "Falkon": "<b>Falkon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, oznaczające \"szlachetność, brawurę, inteligencję\".", "Fuyu": "Pod koniec panowania <a href=\"https://pl.wikipedia.org/wiki/Dynastia_Han#Wschodnia_Dynastia_Han\" target=\"_blank\" rel=\"noopener noreferrer\">Wschodnich Hanów</a>, chiński gubernator wojskowy Gongsun Du w <a href=\"https://pl.wikipedia.org/wiki/Liaotung\" target=\"_blank\" rel=\"noopener noreferrer\">Liaodong</a> wspomógł Buyeo odeprzeć ataki <a href=\"https://pl.wikipedia.org/wiki/Xianbei\" target=\"_blank\" rel=\"noopener noreferrer\">Xianbei</a> na północy i <a href=\"https://pl.wikipedia.org/wiki/Goguryeo\" target=\"_blank\" rel=\"noopener noreferrer\">Goguryeo</a> na wschodzie. Po zniszczeniu rodziny Gongsun&#65279;<a href=\"https://www.wikidata.org/wiki/Q3268466#sitelinks-wikipedia\" target=\"_blank\" rel=\"noopener noreferrer\">(inne języki)</a>, <a href=\"https://pl.wikipedia.org/wiki/Wei_(Okres_Trzech_Kr%C3%B3lestw)\" target=\"_blank\" rel=\"noopener noreferrer\">królestwo Wei</a> wysłało Wuqiu Jian&#65279;<a href=\"https://www.wikidata.org/wiki/Q736639#sitelinks-wikipedia\" target=\"_blank\" rel=\"noopener noreferrer\">(inne języki)</a>, by zaatakował Goguryeo. Oddział trzeciego korpusu ekspedycyjnego dostarczył do Chin szczegółowe informacje na temat Buyeo.", "F": "<b>F</b> (wymowa: <i>ef</i>, <a href=\"https://pl.wikipedia.org/wiki/Minusku%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">minuskuła</a>: <b>f</b>) – szósta litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu łacińskiego</a>, dziewiąta litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_polski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu polskiego</a>. Oznacza zwykle w danym języku <a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_wargowo-z%C4%99bowa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">spółgłoskę szczelinową wargowo-zębową bezdźwięczną</a>, np. [<a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_wargowo-z%C4%99bowa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">f</a>].", "Freyr": "<b>Frejr</b> (także Frej, Frey, Freyr, Yngwe) – bóstwo falliczne z rodu <a href=\"https://pl.wikipedia.org/wiki/Wanowie\" target=\"_blank\" rel=\"noopener noreferrer\">Wanów</a>, bóg urodzaju, roślinności, pokoju, płodności, bogactwa i radości, syn <a href=\"https://pl.wikipedia.org/wiki/Nj%C3%B6r%C3%B0r\" target=\"_blank\" rel=\"noopener noreferrer\">Njörðra</a> i <a href=\"https://pl.wikipedia.org/wiki/Skadi\" target=\"_blank\" rel=\"noopener noreferrer\">Skadi</a> (albo nieznanej z imienia siostry Njörda), brat <a href=\"https://pl.wikipedia.org/wiki/Freja\" target=\"_blank\" rel=\"noopener noreferrer\">Frei</a>. Władca świetlistych Alfów, jego małżonką jest uosabiająca ziemię <a href=\"https://pl.wikipedia.org/wiki/Gerda\" target=\"_blank\" rel=\"noopener noreferrer\">Gerda</a>.", "Faramir": "Pojawia się w jej kolejnych częściach <i><a href=\"https://pl.wikipedia.org/wiki/W%C5%82adca_Pier%C5%9Bcieni\" target=\"_blank\" rel=\"noopener noreferrer\">Władcy Pierścieni</a>:</i> <i><a href=\"https://pl.wikipedia.org/wiki/Dwie_wie%C5%BCe\" target=\"_blank\" rel=\"noopener noreferrer\">Dwóch wieżach</a></i> i <i><a href=\"https://pl.wikipedia.org/wiki/Powr%C3%B3t_kr%C3%B3la\" target=\"_blank\" rel=\"noopener noreferrer\">Powrocie króla</a></i>. Więcej informacji na jego temat zawierają też <i>Dodatki</i> do trzeciego tomu oraz tom dwunasty <i><a href=\"https://pl.wikipedia.org/wiki/Historia_%C5%9Ar%C3%B3dziemia\" target=\"_blank\" rel=\"noopener noreferrer\">Historii Śródziemia</a></i>.", "Febron": "<b>Febron</b>, <b>Febroniusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>Febronius</i>), pochodzące od imienia bóstwa <a href=\"https://pl.wikipedia.org/wiki/Etruskowie\" target=\"_blank\" rel=\"noopener noreferrer\">etruskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Februus\" target=\"_blank\" rel=\"noopener noreferrer\">Februus</a>, oznaczające \"poświęcony bogu Februusowi\". Znane w Polsce od średniowiecza, w formie <i><b>F(i)ebron</b></i>//<i><b>F(i)ebroń</b></i> (zdrobniale F(i)ebronek), także F(i)ebrun//F(i)ebruń oraz Świebron//Świebruń. Występuje również w staroukraińskim jako <i>Фебрунь</i>. Brak męskiego patrona w Kościele katolickim. Patronką tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Febronia_z_Nisibis\" target=\"_blank\" rel=\"noopener noreferrer\">św. Febronia z Nisbis</a>, zmarła w <a href=\"https://pl.wikipedia.org/wiki/304\" target=\"_blank\" rel=\"noopener noreferrer\">304</a> roku śmiercią męczeńską.", "Fengyuan": "Populacja dzielnicy Fengyuan w 2016 roku liczyła 166&#160;778 mieszkańców – 84&#160;268 kobiet i 82&#160;510 mężczyzn. Liczba gospodarstw domowych wynosiła 53&#160;191, co oznacza, że w jednym gospodarstwie zamieszkiwało średnio 3,14 osób.", "Fulko": "<b>Fulko</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, pochodzące od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_p%C3%B3%C5%82nocnogerma%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">skandynawskiego</a> słowa <i>folk</i> oznaczającego „lud, ludzie”. Istnieje kilku świętych o tym imieniu.", "Florus": "Autor zachowanego \"Zarysu dziejów rzymskich\" (<i>Epitomae de Tito Livio bellorum omnium annorum septingentorum libri duo</i>) w 2 księgach. Dla datowania <i>Epitomy</i> pomocna jest wzmianka we wstępie o cesarzu <a href=\"https://pl.wikipedia.org/wiki/Trajan\" target=\"_blank\" rel=\"noopener noreferrer\">Trajanie</a> oraz informacja, że od Cezara <a href=\"https://pl.wikipedia.org/wiki/Oktawian_August\" target=\"_blank\" rel=\"noopener noreferrer\">Augusta</a> do czasów Florusa minęło niewiele mniej niż 200 lat. Głównym źródłem Florusa był <a href=\"https://pl.wikipedia.org/wiki/Tytus_Liwiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Tytus Liwiusz</a>. <a href=\"https://pl.wikipedia.org/wiki/Salustiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Salustiusz</a> dostarczył mu natomiast materiału do opisu <a href=\"https://pl.wikipedia.org/wiki/Wojna_jugurty%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">wojen z Jugurtą</a> i <a href=\"https://pl.wikipedia.org/wiki/Katylina\" target=\"_blank\" rel=\"noopener noreferrer\">Katyliną</a>, a <a href=\"https://pl.wikipedia.org/wiki/Gajusz_Juliusz_Cezar\" target=\"_blank\" rel=\"noopener noreferrer\">Cezar</a> do opisu <a href=\"https://pl.wikipedia.org/wiki/Wojny_galijskie\" target=\"_blank\" rel=\"noopener noreferrer\">podboju Galii</a> i wojny z <a href=\"https://pl.wikipedia.org/wiki/Pompejusz\" target=\"_blank\" rel=\"noopener noreferrer\">Pompejuszem</a>. Jego praca jest krótką syntezą dziejów Rzymu, od założenia miasta aż do <a href=\"https://pl.wikipedia.org/wiki/9\" target=\"_blank\" rel=\"noopener noreferrer\">9 n.e.</a>, napisaną w duchu <a href=\"https://pl.wikipedia.org/wiki/Historiografia\" target=\"_blank\" rel=\"noopener noreferrer\">historiografii</a> <a href=\"https://pl.wikipedia.org/wiki/Stoicyzm\" target=\"_blank\" rel=\"noopener noreferrer\">stoickiej</a>. Florus przedstawił historię narodu rzymskiego według podziału na podstawie analogii z okresami życia człowieka - okres dzieciństwa, młodości, wieku dojrzałego i starości. Dziełko to pod względem formy stanowi przykład kwiecistego stylu retorycznego, panującego w ówczesnej literaturze rzymskiej. Mimo niewielkiej wartości historycznej książka przez długi czas była używana jako podręcznik szkolny, od starożytności aż do XVII wieku. Do naszych czasów zachowała się ponad setka rękopisów.", "Franciszka": "<b>Franciszka</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Franciszek\" target=\"_blank\" rel=\"noopener noreferrer\">Franciszek</a>, pochodzi z języka włoskiego.", "Faustyna": "<b>Faustyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>; żeńska forma imienia <a href=\"https://pl.wikipedia.org/wiki/Faustyn\" target=\"_blank\" rel=\"noopener noreferrer\">Faustyn</a>. Najbardziej znaną imienniczką i patronką tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Faustyna_Kowalska\" target=\"_blank\" rel=\"noopener noreferrer\">Faustyna Kowalska</a>. Łacińska grupa, od której imię to pochodzi (<i>faustus</i> — \"błogi, pomyślny\", ale także <i>faveo, favi, fautum</i> — \"sprzyjać, być przychylnym\") nie ma pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_indoeuropejskie\" target=\"_blank\" rel=\"noopener noreferrer\">indoeuropejskiego</a> oraz pewnych odpowiedników w żadnym języku indoeuropejskim.", "Felicja": "<b>Felicja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Feliks\" target=\"_blank\" rel=\"noopener noreferrer\">Feliks</a>, o tym samym znaczeniu.", "Feliksa": "<b>Feliksa</b> (łac. <i>felix</i> - łaskawy, szczęśliwy) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Feliks\" target=\"_blank\" rel=\"noopener noreferrer\">Feliks</a>.", "Florentyna": "<b>Florentyna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Florentyn\" target=\"_blank\" rel=\"noopener noreferrer\">Florentyn</a>. Patronką tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Florentyna_z_Kartageny\" target=\"_blank\" rel=\"noopener noreferrer\">św. Florentyna z Kartageny</a>, siostra św. <a href=\"https://pl.wikipedia.org/wiki/Izydor_z_Sewilli\" target=\"_blank\" rel=\"noopener noreferrer\">Izydora</a> i św. <a href=\"https://pl.wikipedia.org/wiki/Leander_z_Sewilli\" target=\"_blank\" rel=\"noopener noreferrer\">Leandra z Sewilli</a>.", "Filomena": "<b>Filomena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;φίλος („drogi; miły; przyjaciel”) i μενος („męstwo, siła życiowa”). W Polsce stosowane od XIV wieku.", "Fatima": "<b>Fatima</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>, tłumaczone jako „powstrzymująca się, powściągliwa” lub „odejmować dziecko od piersi”, co w przenośni oznaczałoby kogoś, kto wyszedł z wieku niemowlęcego. Imię to jest w świecie muzułmańskim nadawane na cześć <a href=\"https://pl.wikipedia.org/wiki/Fatima_(c%C3%B3rka_Mahometa)\" target=\"_blank\" rel=\"noopener noreferrer\">ukochanej córki proroka Mahometa</a> i w związku z tym popularne w kulturze <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islamskiej</a>. <a href=\"https://pl.wikipedia.org/wiki/F%C3%A1tima\" target=\"_blank\" rel=\"noopener noreferrer\">Fátima</a> to także nazwa miasta w <a href=\"https://pl.wikipedia.org/wiki/Portugalia\" target=\"_blank\" rel=\"noopener noreferrer\">Portugalii</a>, będącego ośrodkiem <a href=\"https://pl.wikipedia.org/wiki/Kult_maryjny\" target=\"_blank\" rel=\"noopener noreferrer\">kultu maryjnego</a> i celem wielu <a href=\"https://pl.wikipedia.org/wiki/Pielgrzymka\" target=\"_blank\" rel=\"noopener noreferrer\">pielgrzymek</a> <a href=\"https://pl.wikipedia.org/wiki/Katolicyzm\" target=\"_blank\" rel=\"noopener noreferrer\">katolickich</a>.", "Fryderyka": "<b>Fryderyka</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Fryderyk_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Fryderyk</a>.", "Flora": "<b>Flora</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, pochodzące od imienia <a href=\"https://pl.wikipedia.org/wiki/Flora_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiej bogini</a> kwiatów i wiosny. W <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> po raz pierwszy poświadczone w 1375 roku. Patronką imienia jest m.in. <a href=\"https://pl.wikipedia.org/wiki/Flora_i_Maria\" target=\"_blank\" rel=\"noopener noreferrer\">św. Flora z Kordoby</a>.", "Fabiola": "<b>Fabiola</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia łacińskiego, pierwotnie zdrobniała forma imienia <a href=\"https://pl.wikipedia.org/wiki/Fabia\" target=\"_blank\" rel=\"noopener noreferrer\">Fabia</a>.", "Felicyta": "<b>Felicyta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, powstałe od wyrazu pospolitego <em>felicitas</em>, „urodzaj”, „szczęśliwość”, „błogosławieństwo”. Jedną z form zdrobniałych jest być może imię <a href=\"https://pl.wikipedia.org/wiki/Zyta\" target=\"_blank\" rel=\"noopener noreferrer\">Zyta</a>, obecnie funkcjonujące samodzielnie. Patronką tego imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/Felicyta_z_Kartaginy\" target=\"_blank\" rel=\"noopener noreferrer\">Felicyta z Kartaginy</a> (†203).", "Filipina": "<b>Filipina</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Filip\" target=\"_blank\" rel=\"noopener noreferrer\">Filip</a>. Patronką tego imienia jest św. Róża Filipina Duchesne (1769–1852).", "Fiona": "Uważa się, że imię to jest <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">zlatynizowaną</a> formą <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_irlandzki\" target=\"_blank\" rel=\"noopener noreferrer\">irlandzkiego</a> słowa <i>fionn</i>, oznaczającego coś „białego”, „sprawiedliwego”, „uczciwego”. Imię <i>Fiona</i> jest też czasami używane w formie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">zanglicyzowanej</a>, pochodnej od oryginalnej formy irlandzkiej imienia <i>Fíona</i>. Występuje także tendencja do wymiennego używania rzeczywistego <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_gaelicki_szkocki\" target=\"_blank\" rel=\"noopener noreferrer\">szkockiego</a> imienia <i>Fionnghal</i> i imienia <i>Fiona</i> (jest też możliwe, że imię <i>Fiona</i> było utworzone na bazie imienia <i>Fionnghal</i>).", "Fryda": "<b>Fryda</b> – skrócona forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Fryderyka\" target=\"_blank\" rel=\"noopener noreferrer\">Fryderyka</a>, <a href=\"https://pl.wikipedia.org/wiki/Elfryda\" target=\"_blank\" rel=\"noopener noreferrer\">Elfryda</a>, <a href=\"https://pl.wikipedia.org/wiki/Alfreda\" target=\"_blank\" rel=\"noopener noreferrer\">Alfreda</a>, <a href=\"https://pl.wikipedia.org/wiki/Fredegunda\" target=\"_blank\" rel=\"noopener noreferrer\">Fredegunda</a> lub Frydolina.", "Florianna": "<b>Florianna</b>, <b>Floriana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie; żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Florian\" target=\"_blank\" rel=\"noopener noreferrer\">Florian</a>, które z kolei pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>florus</i> – „kwitnący” i oznacza „należący do <i>Florusa</i>”. <b>Florianna</b> jest nadawana w Polsce od <a href=\"https://pl.wikipedia.org/wiki/XV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XV wieku</a>, a po raz pierwszy zapisana była w formie <i><b>Floryjana</b></i>. Zanotowano także zdrobnienie Floszka, oraz drugie, Tworka, które mogło pochodzić od Florianny z substytucją polską (jak Florian → Tworzyjan), lub też od imion rodzimych zaczynających się na <i>Tworzy-</i>.", "Fabiana": "<b>Fabiana</b> (również <b>Pabiana</b>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od nazwy <a href=\"https://pl.wikipedia.org/wiki/Cesarstwo_Rzymskie\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <a href=\"https://pl.wikipedia.org/wiki/Fabiusze\" target=\"_blank\" rel=\"noopener noreferrer\">Fabiuszów</a>. Żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Fabian\" target=\"_blank\" rel=\"noopener noreferrer\">Fabian</a>.", "Faina": "<b>Faina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie niejasnego pochodzenia, być może wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> imienia mitologicznego <i>Φαεννα (Phaenna)</i>, pochodzącego od <i>φαεινος (phaeinos)</i> – \"błyszczący, lśniący\". Imię to było przede wszystkim używane w Rosji. Jego patronką jest św. Faina, wspominana razem ze św. Aleksandrą, Klaudią, Eufrazją, Matroną, Julitą, Tekuzą i Teodotem.", "Flawia": "<b>Flawia</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Flawiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Flawiusz</a>. Istnieje kilka świętych patronek tego imienia.", "Florencja": "<b>Florencja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego „kwitnący, pomyślny”.", "Fortunata": "<b>Fortunata</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Fortunat\" target=\"_blank\" rel=\"noopener noreferrer\">Fortunat</a>, oznacza „uszczęśliwona”.", "Filipa": "<b>Filipa</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Filip\" target=\"_blank\" rel=\"noopener noreferrer\">Filip</a>.", "Freja": "Od staronordyckiego imienia bogini „Vanadís” pochodzi nazwa pierwiastka chemicznego <a href=\"https://pl.wikipedia.org/wiki/Wanad\" target=\"_blank\" rel=\"noopener noreferrer\">wanad</a>. Nazwę zaproponował w 1831, szwedzki chemik <a href=\"https://pl.wikipedia.org/wiki/Nils_Gabriel_Sefstr%C3%B6m\" target=\"_blank\" rel=\"noopener noreferrer\">Nils Gabriel Sefström</a>. Nazwę <a href=\"https://pl.wikipedia.org/wiki/(240)_Vanadis\" target=\"_blank\" rel=\"noopener noreferrer\">Vanadis (240)</a> nosi również <a href=\"https://pl.wikipedia.org/wiki/Planetoida\" target=\"_blank\" rel=\"noopener noreferrer\">planetoida</a> odkryta w 1884 roku przez <a href=\"https://pl.wikipedia.org/wiki/Alphonse_Louis_Nicolas_Borrelly\" target=\"_blank\" rel=\"noopener noreferrer\">Alphonse Borrelly’ego</a>.", "Fabia": "<b>Fabia</b> – żeński odpowiednik łacińskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Fabiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Fabiusz</a>. Patronem tego imienia jest bł. Fabiusz (zm. w <a href=\"https://pl.wikipedia.org/wiki/303\" target=\"_blank\" rel=\"noopener noreferrer\">303</a> roku).", "Felicjana": "<b>Felicjana</b>, <b>Felicjanna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Felicjan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Felicjan</a>. <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">Imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/24_listopada\" target=\"_blank\" rel=\"noopener noreferrer\">24 listopada</a>, jako wspomnienie <a href=\"https://pl.wikipedia.org/wiki/Felicjana_de_Uribe_Orbe\" target=\"_blank\" rel=\"noopener noreferrer\">bł. Felicjany (Felicjanny) de Uribe Orbe</a>, karmelitańskiej siostry miłosierdzia.", "Freyja": "Od staronordyckiego imienia bogini „Vanadís” pochodzi nazwa pierwiastka chemicznego <a href=\"https://pl.wikipedia.org/wiki/Wanad\" target=\"_blank\" rel=\"noopener noreferrer\">wanad</a>. Nazwę zaproponował w 1831, szwedzki chemik <a href=\"https://pl.wikipedia.org/wiki/Nils_Gabriel_Sefstr%C3%B6m\" target=\"_blank\" rel=\"noopener noreferrer\">Nils Gabriel Sefström</a>. Nazwę <a href=\"https://pl.wikipedia.org/wiki/(240)_Vanadis\" target=\"_blank\" rel=\"noopener noreferrer\">Vanadis (240)</a> nosi również <a href=\"https://pl.wikipedia.org/wiki/Planetoida\" target=\"_blank\" rel=\"noopener noreferrer\">planetoida</a> odkryta w 1884 roku przez <a href=\"https://pl.wikipedia.org/wiki/Alphonse_Louis_Nicolas_Borrelly\" target=\"_blank\" rel=\"noopener noreferrer\">Alphonse Borrelly’ego</a>.", "Febronia": "<b>Febronia</b> – pochodzące z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, przypuszczalnie wywiedzione od imienia bóstwa <a href=\"https://pl.wikipedia.org/wiki/Etruskowie\" target=\"_blank\" rel=\"noopener noreferrer\">etruskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Februus\" target=\"_blank\" rel=\"noopener noreferrer\">Februusa</a>. Znane w Polsce od średniowiecza, również w formach Fiebronija, Febrocha i Feberka.", "Fatiha": "<b>Fatiha</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> <b>ﻓﺘﻴﺤﺔ</b>) – arabskie imię żeńskie. Pochodzi od <a href=\"https://pl.wikipedia.org/wiki/Tytu%C5%82_(literaturoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">tytułu</a> pierwszej sury <a href=\"https://pl.wikipedia.org/wiki/Koran\" target=\"_blank\" rel=\"noopener noreferrer\">Koranu</a> <a href=\"https://pl.wikipedia.org/wiki/Al-Fatiha\" target=\"_blank\" rel=\"noopener noreferrer\">Al-Fatihy</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> الفاتحة).", "Fidelia": "<b>Fidelisa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>fidelis</i>, ‘wierny, pewny’. Oznacza kobietę „pełną wiary”.", "Fara": "W <a href=\"https://pl.wikipedia.org/wiki/Etnolekt_%C5%9Bl%C4%85ski\" target=\"_blank\" rel=\"noopener noreferrer\">etnolekcie śląskim</a> fara oznacza budynek probostwa (podobnie jak w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">języku czeskim</a>), a farorzem mianuje się proboszcza danej parafii (czeski: farář).", "Felina": "<b>Felina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie; żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Felin_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Felin</a>, którego patronem jest św. Felin, towarzysz św. Gratyniana i razem z nim patron <a href=\"https://pl.wikipedia.org/wiki/Arona_(W%C5%82ochy)\" target=\"_blank\" rel=\"noopener noreferrer\">Arony</a>.", "Fidelisa": "<b>Fidelisa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>fidelis</i>, ‘wierny, pewny’. Oznacza kobietę „pełną wiary”.", "Filadelfia": "<b>Filadelfia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, od <i>φιλεω (fileo)</i> - \"kochać\" i <i>αδελφος (adelfos)</i> - \"brat\", co oznaczało \"braterska miłość\". Patronem tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Filadelf\" target=\"_blank\" rel=\"noopener noreferrer\">Filadelf</a>, wspominany razem ze swoimi braćmi, św. Alfiuszem i <a href=\"https://pl.wikipedia.org/wiki/Cyryn_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Cyrynem</a> (<a href=\"https://pl.wikipedia.org/wiki/III_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">III wiek</a>).", "Firmina": "<b>Firmina</b> — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające \"należąca do <a href=\"https://pl.wikipedia.org/wiki/Firmus_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Firmusa</a>\" lub stanowiące żeńskie spieszczenie od imienia <a href=\"https://pl.wikipedia.org/wiki/Firmus_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Firmus</a>, które z kolei pochodzi od słowa <i>firmus</i> — \"mocny, pewny, stały, trwały\".", "Fumiko": "<b>Fumiko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;ふみこ, フミコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Fausta": "<b>Fausta</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Faust_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Faust</a>. Łacińska grupa, od której imię to pochodzi (<i>faustus</i> — \"błogi, pomyślny\", ale także <i>faveo, favi, fautum</i> — \"sprzyjać, być przychylnym\") nie ma pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_indoeuropejskie\" target=\"_blank\" rel=\"noopener noreferrer\">indoeuropejskiego</a> oraz pewnych odpowiedników w żadnym języku indoeuropejskim.", "Filona": "<b>Filona</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Filon\" target=\"_blank\" rel=\"noopener noreferrer\">Filon</a>, które pochodzi od <i>φιλεω (fileo)</i> – \"kochać\" i oznacza \"kochająca\". Patronem tego imienia jest św. Filon, wspominany razem ze św. Agatopodem.", "Flawiana": "<b>Flawiana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od nazwy <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <a href=\"https://pl.wikipedia.org/wiki/Flawiusze\" target=\"_blank\" rel=\"noopener noreferrer\">Flawiuszów</a>. Oznacza \"należąca do Flawiusza, pochodząca od Flawiusza\". Patronką tego imienia jest św. Flawiana z <a href=\"https://pl.wikipedia.org/wiki/Auxerre\" target=\"_blank\" rel=\"noopener noreferrer\">Auxerre</a>.", "Fumi": "<b>Fumi</b> - japońskie imię żeńskie. Może być pisane znakami: 文; 史 lub kaną ふみ.", "Feba": "<b>Feba</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia greckiego, od <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> Φοιβη (Foibe), co oznaczało „jasna, czysta”. Imię to nosiło kilka postaci z <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii greckiej</a>. Od jednej z nich – tytanidy – pochodzi nazwa księżyca <a href=\"https://pl.wikipedia.org/wiki/Saturn\" target=\"_blank\" rel=\"noopener noreferrer\">Saturna</a>, <a href=\"https://pl.wikipedia.org/wiki/Febe_(ksi%C4%99%C5%BCyc)\" target=\"_blank\" rel=\"noopener noreferrer\">Febe</a>. Patronką tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Febe_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">św. Feba</a> z <a href=\"https://pl.wikipedia.org/wiki/Korynt\" target=\"_blank\" rel=\"noopener noreferrer\">Koryntu</a> wymieniona przez apostoła <a href=\"https://pl.wikipedia.org/wiki/Pawe%C5%82_z_Tarsu\" target=\"_blank\" rel=\"noopener noreferrer\">Pawła</a> w <a href=\"https://pl.wikipedia.org/wiki/List_do_Rzymian\" target=\"_blank\" rel=\"noopener noreferrer\">Liście do Rzymian</a> 16:1 jako <a href=\"https://pl.wikipedia.org/wiki/Diakon\" target=\"_blank\" rel=\"noopener noreferrer\">diakonisa</a> wczesnego Kościoła <a href=\"https://pl.wikipedia.org/wiki/Chrze%C5%9Bcija%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">chrześcijańskiego</a>.", "Fujiko": "<b>Fujiko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;ふじこ, フジコ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">japońskie imię żeńskie</a>.", "Fotyna": "<b>Fotyna</b> – żeńska forma imienia <a href=\"https://pl.wikipedia.org/wiki/Fotyn\" target=\"_blank\" rel=\"noopener noreferrer\">Fotyn</a>, pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodząca się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;φως, oznaczającego „światło, jasność”. Fotyna oznacza też „należąca do Focjusza, pochodząca od Focjusza”, przy czym imię Focjusz powstało bezpośrednio od słowa <i>phōs, phōtós</i>.", "Fatima Zahra": "<b>Fatima bint Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;فاطمة بنت محمد&#8206;, ur. pomiędzy <a href=\"https://pl.wikipedia.org/wiki/600\" target=\"_blank\" rel=\"noopener noreferrer\">600</a> a <a href=\"https://pl.wikipedia.org/wiki/615\" target=\"_blank\" rel=\"noopener noreferrer\">615</a>, zm. <a href=\"https://pl.wikipedia.org/wiki/632\" target=\"_blank\" rel=\"noopener noreferrer\">632</a>) – córka proroka <a href=\"https://pl.wikipedia.org/wiki/Mahomet\" target=\"_blank\" rel=\"noopener noreferrer\">Mahometa</a> i jego żony <a href=\"https://pl.wikipedia.org/wiki/Chadid%C5%BCa\" target=\"_blank\" rel=\"noopener noreferrer\">Chadidży</a>. W 625 poślubiła kuzyna swego ojca, <a href=\"https://pl.wikipedia.org/wiki/Ali_ibn_Abi_Talib\" target=\"_blank\" rel=\"noopener noreferrer\">Alego</a>, ostatniego kalifa prawowiernego i pierwszego <a href=\"https://pl.wikipedia.org/wiki/Imam_(szyizm)\" target=\"_blank\" rel=\"noopener noreferrer\">imama</a>. Została matką <a href=\"https://pl.wikipedia.org/wiki/Husajn_ibn_Ali\" target=\"_blank\" rel=\"noopener noreferrer\">Husajna</a>, <a href=\"https://pl.wikipedia.org/wiki/Hasan_ibn_Ali\" target=\"_blank\" rel=\"noopener noreferrer\">Hasana</a>, Moszina i Zajnab. Członek <a href=\"https://pl.wikipedia.org/wiki/Ahl_al-Bajt\" target=\"_blank\" rel=\"noopener noreferrer\">rodziny</a> Mahometa. <a href=\"https://pl.wikipedia.org/wiki/Alidzi\" target=\"_blank\" rel=\"noopener noreferrer\">Potomkowie</a> Mahometa i wszyscy <a href=\"https://pl.wikipedia.org/wiki/Imam_(szyizm)\" target=\"_blank\" rel=\"noopener noreferrer\">imamowie</a> wywodzą się od niej i Alego.", "Floryna": "<b>Floryna</b> — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia łacińskiego, pierwotnie <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">łaciński przydomek</a> pochodzący od imienia <i>Florus</i> („kwitnący”) i oznaczający „pochodząca od <i>Florusa</i>, córka <i>Florusa”</i>. Patronką imienia jest św. Floryna z Brioud (<a href=\"https://pl.wikipedia.org/wiki/Owernia\" target=\"_blank\" rel=\"noopener noreferrer\">Owernia</a>). Męski odpowiednik: <a href=\"https://pl.wikipedia.org/wiki/Floryn\" target=\"_blank\" rel=\"noopener noreferrer\">Floryn</a>."};
